"use client";

import React, { useState } from 'react';
import { useQuery, useMutation } from '@tanstack/react-query';
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Label } from "@/components/ui/label";
import { Loader2, Save, FileSpreadsheet } from "lucide-react";
import { toast } from 'sonner';

export default function BalanceSheetPage() {
    const [selectedContractor, setSelectedContractor] = useState<string>('');
    const [selectedStore, setSelectedStore] = useState<string>('');
    const [month, setMonth] = useState<string>(new Date().toISOString().slice(0, 7)); // YYYY-MM
    const [reportData, setReportData] = useState<any>(null);

    // --- FETCH DATA ---
    const { data: contractorsData } = useQuery({
        queryKey: ['contractors'],
        queryFn: async () => (await fetch('/api/contractors?page=1&limit=1000')).json()
    });
    const contractors = Array.isArray(contractorsData?.contractors) ? contractorsData.contractors : [];

    const { data: stores = [] } = useQuery({
        queryKey: ['stores'],
        queryFn: async () => (await fetch('/api/stores')).json()
    });

    // --- MUTATIONS ---
    const generateMutation = useMutation({
        mutationFn: async () => {
            const res = await fetch('/api/inventory/balance-sheet/generate', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    contractorId: selectedContractor,
                    storeId: selectedStore,
                    month
                })
            });
            if (!res.ok) throw new Error('Failed to generate report');
            return res.json();
        },
        onSuccess: (data) => {
            setReportData(data);
            toast.success("Report generated");
        },
        onError: () => toast.error("Generation failed")
    });

    const saveMutation = useMutation({
        mutationFn: async () => {
            if (!reportData) return;
            const res = await fetch('/api/inventory/balance-sheet', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    contractorId: selectedContractor,
                    storeId: selectedStore,
                    month,
                    items: reportData.items
                })
            });
            if (!res.ok) throw new Error('Failed to save report');
            return res.json();
        },
        onSuccess: () => {
            toast.success("Balance Sheet Saved Successfully");
        },
        onError: () => toast.error("Save failed")
    });

    const handleGenerate = () => {
        if (!selectedContractor || !selectedStore || !month) {
            toast.error("Please select all fields");
            return;
        }
        generateMutation.mutate();
    };

    return (
        <div className="p-6 max-w-6xl mx-auto space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">Monthly Balance Sheet</h1>
                    <p className="text-slate-500">Generate and freeze monthly material balances.</p>
                </div>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle className="text-sm font-medium uppercase text-slate-500">Report Criteria</CardTitle>
                </CardHeader>
                <CardContent className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                    <div className="space-y-2">
                        <Label>Contractor</Label>
                        <Select value={selectedContractor} onValueChange={setSelectedContractor}>
                            <SelectTrigger>
                                <SelectValue placeholder="Select Contractor" />
                            </SelectTrigger>
                            <SelectContent>
                                {contractors.map((c: any) => (
                                    <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label>Store</Label>
                        <Select value={selectedStore} onValueChange={setSelectedStore}>
                            <SelectTrigger>
                                <SelectValue placeholder="Select Store" />
                            </SelectTrigger>
                            <SelectContent>
                                {stores.map((s: any) => (
                                    <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label>Month</Label>
                        <Input
                            type="month"
                            value={month}
                            onChange={(e) => setMonth(e.target.value)}
                        />
                    </div>

                    <Button onClick={handleGenerate} disabled={generateMutation.isPending}>
                        {generateMutation.isPending ? <Loader2 className="animate-spin w-4 h-4 mr-2" /> : <FileSpreadsheet className="w-4 h-4 mr-2" />}
                        Generate Report
                    </Button>
                </CardContent>
            </Card>

            {reportData && (
                <div className="space-y-4 animate-in slide-in-from-bottom-5 fade-in duration-500">
                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between pb-2">
                            <CardTitle>Report Preview: {month}</CardTitle>
                            <Button variant="default" onClick={() => saveMutation.mutate()} disabled={saveMutation.isPending}>
                                <Save className="w-4 h-4 mr-2" />
                                {saveMutation.isPending ? "Saving..." : "Save & Freeze"}
                            </Button>
                        </CardHeader>
                        <CardContent>
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Item Code</TableHead>
                                        <TableHead>Description</TableHead>
                                        <TableHead className="text-right">Opening</TableHead>
                                        <TableHead className="text-right">Received</TableHead>
                                        <TableHead className="text-right">Used</TableHead>
                                        <TableHead className="text-right">Wastage</TableHead>
                                        <TableHead className="text-right">Returned</TableHead>
                                        <TableHead className="text-right font-bold bg-slate-50">Closing</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {reportData.items.length === 0 ? (
                                        <TableRow>
                                            <TableCell colSpan={8} className="text-center py-8 text-slate-500">
                                                No activity found for this month.
                                            </TableCell>
                                        </TableRow>
                                    ) : (
                                        reportData.items.map((item: any) => (
                                            <TableRow key={item.itemId}>
                                                <TableCell className="font-mono text-xs">{item.itemCode}</TableCell>
                                                <TableCell>{item.itemName} <span className="text-xs text-slate-400">({item.unit})</span></TableCell>
                                                <TableCell className="text-right text-slate-600">{item.opening}</TableCell>
                                                <TableCell className="text-right text-blue-600 font-medium">+{item.received}</TableCell>
                                                <TableCell className="text-right text-amber-600">-{item.used}</TableCell>
                                                <TableCell className="text-right text-orange-600">-{item.wastage}</TableCell>
                                                <TableCell className="text-right text-green-600">-{item.returned}</TableCell>
                                                <TableCell className="text-right font-bold bg-slate-50 border-l">{item.closing.toFixed(2)}</TableCell>
                                            </TableRow>
                                        ))
                                    )}
                                </TableBody>
                            </Table>
                        </CardContent>
                    </Card>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Card, CardContent } from "@/components/ui/card";
import { toast } from "sonner";
import { Loader2, Save, Search, RefreshCw } from "lucide-react";
import Sidebar from '@/components/Sidebar';
import Header from '@/components/Header';
import { Badge } from "@/components/ui/badge";

interface InventoryItem {
    id: string;
    code: string;
    name: string;
    category: string;
    unit: string;
}

interface StockRecord {
    itemId: string;
    quantity: number;
}

export default function InitialStockPage() {
    const queryClient = useQueryClient();
    const [selectedStore, setSelectedStore] = useState<string>("");
    const [searchTerm, setSearchTerm] = useState("");
    const [stockValues, setStockValues] = useState<Record<string, string>>({});
    // Key: itemId, Value: string input (to allow empty)

    // Fetch Stores
    const { data: stores = [] } = useQuery({
        queryKey: ["stores"],
        queryFn: async () => {
            const res = await fetch("/api/stores?page=1&limit=1000");
            const data = await res.json();
            return Array.isArray(data) ? data : (data.stores || []);
        }
    });

    // Fetch All Items
    const { data: items = [], isLoading: isLoadingItems } = useQuery<InventoryItem[]>({
        queryKey: ["inventory-items"],
        queryFn: async () => {
            const res = await fetch("/api/inventory/items?page=1&limit=1000");
            const data = await res.json();
            return Array.isArray(data) ? data : (data.items || []);
        }
    });

    // Fetch Current Stock when store changes
    const { data: currentStocks = [], isLoading: isLoadingStock, refetch: refetchStock } = useQuery<any[]>({
        queryKey: ["current-stock", selectedStore],
        queryFn: async () => {
            if (!selectedStore) return [];
            const res = await fetch(`/api/inventory/stock?storeId=${selectedStore}`, { cache: 'no-store' });
            const data = await res.json();
            return Array.isArray(data) ? data : (data.stock || data.data || []);
        },
        enabled: !!selectedStore
    });

    // Initialize inputs when current stock loads
    useEffect(() => {
        if (selectedStore && currentStocks && items.length > 0) {
            const initialValues: Record<string, string> = {};
            items.forEach(item => {
                const stock = currentStocks.find((s: any) => s.itemId === item.id);
                initialValues[item.id] = stock ? stock.quantity.toString() : "0";
            });
            setStockValues(initialValues);
        } else if (!selectedStore) {
            // Clear when no store selected
            setStockValues({});
        }
        // Only run when selectedStore changes or when data first loads
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedStore]);


    const saveMutation = useMutation({
        mutationFn: async (payload: any) => {
            const res = await fetch("/api/inventory/stock", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json",
                    "x-user-id": "USER_ID_PLACEHOLDER" // Ideally from Auth Context
                },
                body: JSON.stringify(payload)
            });
            if (!res.ok) throw new Error("Failed to update stock");
            return res.json();
        },
        onSuccess: (data) => {
            toast.success(`Stock updated successfully. ${data.itemsUpdated} items affected.`);
            refetchStock();
        },
        onError: () => toast.error("Failed to update stock")
    });

    const handleQuantityChange = (itemId: string, val: string) => {
        setStockValues(prev => ({ ...prev, [itemId]: val }));
    };

    const handleSave = () => {
        if (!selectedStore) {
            toast.error("Please select a store");
            return;
        }

        // Prepare changes
        // We send ALL items or just changed ones?
        // Bulk update API handles all. Let's send all non-empty ones to be safe/consistent.
        const itemsToUpdate = items.map(item => ({
            itemId: item.id,
            quantity: parseFloat(stockValues[item.id] || "0")
        })).filter(i => !isNaN(i.quantity));

        saveMutation.mutate({
            storeId: selectedStore,
            items: itemsToUpdate,
            reason: "Initial Stock Setup / Adjustment"
        });
    };

    const filteredItems = items.filter(item =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        item.code.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="flex h-screen bg-slate-50 overflow-hidden">
            <Sidebar />
            <main className="flex-1 flex flex-col min-w-0 h-full">
                <Header />
                <div className="flex-1 overflow-y-auto p-4 md:p-8">
                    <div className="max-w-7xl mx-auto space-y-6">

                        <div className="flex justify-between items-center">
                            <div>
                                <h1 className="text-2xl font-bold text-slate-900">Initial Stock Setup</h1>
                                <p className="text-slate-500">Set physical stock counts for stores (Fresh Start)</p>
                            </div>
                            <Button onClick={handleSave} disabled={saveMutation.isPending || !selectedStore}>
                                {saveMutation.isPending ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Save className="w-4 h-4 mr-2" />}
                                Update All Stock
                            </Button>
                        </div>

                        {/* Controls */}
                        <Card>
                            <CardContent className="p-6 flex flex-col md:flex-row gap-4 items-end">
                                <div className="w-full md:w-1/3 space-y-2">
                                    <select
                                        className="flex h-10 w-full items-center justify-between rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50"
                                        value={selectedStore}
                                        onChange={(e) => setSelectedStore(e.target.value)}
                                    >
                                        <option value="" disabled>Select Store...</option>
                                        {stores.map((store: any) => (
                                            <option key={store.id} value={store.id}>{store.name}</option>
                                        ))}
                                    </select>
                                </div>

                                <div className="w-full md:w-1/3 space-y-2">
                                    <label className="text-sm font-medium">Search Items</label>
                                    <div className="relative">
                                        <Search className="absolute left-2 top-2.5 h-4 w-4 text-slate-400" />
                                        <Input
                                            placeholder="Search by code or name..."
                                            className="pl-8"
                                            value={searchTerm}
                                            onChange={(e) => setSearchTerm(e.target.value)}
                                        />
                                    </div>
                                </div>
                            </CardContent>
                        </Card>

                        {/* Table */}
                        <Card className="overflow-hidden">
                            <div className="max-h-[600px] overflow-y-auto relative">
                                {!selectedStore ? (
                                    <div className="p-12 text-center text-slate-500">
                                        Please select a store to view stock
                                    </div>
                                ) : isLoadingItems || isLoadingStock ? (
                                    <div className="p-12 text-center flex justify-center">
                                        <Loader2 className="w-8 h-8 animate-spin text-blue-500" />
                                    </div>
                                ) : (
                                    <table className="w-full text-sm text-left">
                                        <thead className="text-xs text-slate-500 uppercase bg-slate-50 sticky top-0 z-10">
                                            <tr>
                                                <th className="px-6 py-3">Code</th>
                                                <th className="px-6 py-3">Item Name</th>
                                                <th className="px-6 py-3">Category</th>
                                                <th className="px-6 py-3 text-right">Current System Qty</th>
                                                <th className="px-6 py-3 text-right bg-blue-50/50">New Physical Qty</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {filteredItems.map((item) => {
                                                const currentStock = currentStocks?.find((s: any) => s.itemId === item.id);
                                                const currentQty = currentStock ? currentStock.quantity : 0;
                                                const inputValue = stockValues[item.id] ?? "0";
                                                const isChanged = parseFloat(inputValue) !== currentQty;

                                                return (
                                                    <tr key={item.id} className="border-b hover:bg-slate-50/50">
                                                        <td className="px-6 py-4 font-medium">{item.code}</td>
                                                        <td className="px-6 py-4">{item.name}</td>
                                                        <td className="px-6 py-4">{item.category}</td>
                                                        <td className="px-6 py-4 text-right">
                                                            <Badge variant="outline" className="bg-slate-100">
                                                                {currentQty} {item.unit}
                                                            </Badge>
                                                        </td>
                                                        <td className={`px-6 py-4 text-right ${isChanged ? 'bg-blue-50' : ''}`}>
                                                            <div className="flex justify-end items-center gap-2">
                                                                <Input
                                                                    type="number"
                                                                    className={`w-32 text-right ${isChanged ? 'border-blue-400 font-bold' : ''}`}
                                                                    value={inputValue}
                                                                    onChange={(e) => handleQuantityChange(item.id, e.target.value)}
                                                                />
                                                                <span className="text-slate-500 w-8">{item.unit}</span>
                                                            </div>
                                                        </td>
                                                    </tr>
                                                );
                                            })}
                                            {filteredItems.length === 0 && (
                                                <tr>
                                                    <td colSpan={5} className="text-center py-8 text-slate-500">
                                                        No items found
                                                    </td>
                                                </tr>
                                            )}
                                        </tbody>
                                    </table>
                                )}
                            </div>
                        </Card>

                    </div>
                </div>
            </main>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Label } from "@/components/ui/label";
import { Trash, Plus, Save, Package } from "lucide-react";
import { toast } from 'sonner';
import { useRouter } from 'next/navigation';

export default function MaterialIssuePage() {
    const queryClient = useQueryClient();
    const router = useRouter();

    // Form State
    const [selectedContractor, setSelectedContractor] = useState<string>('');
    const [selectedStore, setSelectedStore] = useState<string>('');
    const [month, setMonth] = useState<string>(new Date().toISOString().slice(0, 7)); // YYYY-MM

    // Items State
    const [rows, setRows] = useState<Array<{ itemId: string; quantity: number; unit: string; name: string }>>([
        { itemId: '', quantity: 0, unit: '', name: '' }
    ]);

    // Filters
    const [itemCategoryFilter, setItemCategoryFilter] = useState("ALL");
    const [itemJobFilter, setItemJobFilter] = useState("ALL");

    // --- FETCH DATA ---
    const { data: contractorsData } = useQuery({
        queryKey: ['contractors'],
        queryFn: async () => (await fetch('/api/contractors?page=1&limit=1000')).json()
    });
    const contractors = Array.isArray(contractorsData?.contractors) ? contractorsData.contractors : [];

    const { data: stores = [] } = useQuery({
        queryKey: ['stores'],
        queryFn: async () => (await fetch('/api/stores')).json()
    });

    const { data: items = [] } = useQuery({
        queryKey: ['inventory-items'],
        queryFn: async () => (await fetch('/api/inventory/items')).json()
    });

    // --- MUTATION ---
    const issueMutation = useMutation({
        mutationFn: async (data: any) => {
            const res = await fetch('/api/inventory/issue', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data)
            });
            if (!res.ok) {
                const err = await res.json();
                throw new Error(err.message || 'Failed to issue materials');
            }
            return res.json();
        },
        onSuccess: () => {
            toast.success("Materials issued successfully!");
            // Reset form
            setRows([{ itemId: '', quantity: 0, unit: '', name: '' }]);
            setSelectedContractor('');
            // Optional: Redirect or stay
        },
        onError: (err: any) => {
            toast.error(err.message);
        }
    });

    // --- HANDLERS ---
    const handleAddRow = () => {
        setRows([...rows, { itemId: '', quantity: 0, unit: '', name: '' }]);
    };

    const handleRemoveRow = (idx: number) => {
        if (rows.length === 1) return; // Keep at least one row
        setRows(rows.filter((_, i) => i !== idx));
    };

    const handleItemChange = (idx: number, itemId: string) => {
        const item = items.find((i: any) => i.id === itemId);
        const newRows = [...rows];
        newRows[idx] = {
            ...newRows[idx],
            itemId,
            name: item?.name || '',
            unit: item?.unit || 'Nos' // Default unit if not found
        };
        setRows(newRows);
    };

    const handleQuantityChange = (idx: number, val: string) => {
        const newRows = [...rows];
        newRows[idx].quantity = parseFloat(val) || 0;
        setRows(newRows);
    };

    const handleSubmit = () => {
        if (!selectedContractor || !selectedStore) {
            toast.error("Please select Contractor and Store");
            return;
        }

        // Validate items
        const validItems = rows.filter(r => r.itemId && r.quantity > 0);
        if (validItems.length === 0) {
            toast.error("Please add at least one valid item");
            return;
        }

        issueMutation.mutate({
            contractorId: selectedContractor,
            storeId: selectedStore,
            month,
            items: validItems.map(r => ({
                itemId: r.itemId,
                quantity: r.quantity,
                unit: r.unit
            }))
        });
    };

    return (
        <div className="p-6 max-w-5xl mx-auto space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">Issue Materials</h1>
                    <p className="text-slate-500">Issue monthly stock to contractors.</p>
                </div>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle className="text-sm font-medium uppercase text-slate-500">Config</CardTitle>
                </CardHeader>
                <CardContent className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="space-y-2">
                        <Label>Contractor</Label>
                        <Select value={selectedContractor} onValueChange={setSelectedContractor}>
                            <SelectTrigger>
                                <SelectValue placeholder="Select Contractor" />
                            </SelectTrigger>
                            <SelectContent>
                                {contractors.map((c: any) => (
                                    <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label>Store</Label>
                        <Select value={selectedStore} onValueChange={setSelectedStore}>
                            <SelectTrigger>
                                <SelectValue placeholder="Select Store" />
                            </SelectTrigger>
                            <SelectContent>
                                {stores.map((s: any) => (
                                    <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label>Month</Label>
                        <Input
                            type="month"
                            value={month}
                            onChange={(e) => setMonth(e.target.value)}
                        />
                    </div>
                </CardContent>
            </Card>

            <Card>
                <CardContent className="p-0">
                    <div className="p-4 border-b bg-slate-50 flex gap-4 items-center">
                        <Label className="text-xs font-semibold text-slate-500">Filter Items:</Label>
                        <Select value={itemCategoryFilter} onValueChange={setItemCategoryFilter}>
                            <SelectTrigger className="h-8 w-40 text-xs"><SelectValue placeholder="Category" /></SelectTrigger>
                            <SelectContent>
                                <SelectItem value="ALL">All Categories</SelectItem>
                                <SelectItem value="CABLES">Cables & Wires</SelectItem>
                                <SelectItem value="POLES">Poles</SelectItem>
                                <SelectItem value="FIBER_ACCESSORIES">Fiber Accessories</SelectItem>
                                <SelectItem value="COPPER_ACCESSORIES">Copper Accessories</SelectItem>
                                <SelectItem value="HARDWARE">Hardware</SelectItem>
                                <SelectItem value="EQUIPMENT">Equipment</SelectItem>
                                <SelectItem value="OTHERS">Others</SelectItem>
                            </SelectContent>
                        </Select>
                        <Select value={itemJobFilter} onValueChange={setItemJobFilter}>
                            <SelectTrigger className="h-8 w-40 text-xs"><SelectValue placeholder="Job Type" /></SelectTrigger>
                            <SelectContent>
                                <SelectItem value="ALL">All Jobs</SelectItem>
                                <SelectItem value="FTTH">FTTH</SelectItem>
                                <SelectItem value="PSTN">PSTN</SelectItem>
                                <SelectItem value="OSP">OSP</SelectItem>
                                <SelectItem value="OTHERS">Others</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead className="w-[40%]">Item Name</TableHead>
                                <TableHead className="w-[20%]">Unit</TableHead>
                                <TableHead className="w-[20%]">Quantity</TableHead>
                                <TableHead className="w-[10%]">Action</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {rows.map((row, idx) => (
                                <TableRow key={idx}>
                                    <TableCell>
                                        <Select value={row.itemId} onValueChange={(v) => handleItemChange(idx, v)}>
                                            <SelectTrigger>
                                                <SelectValue placeholder="Select Item" />
                                            </SelectTrigger>
                                            <SelectContent className="max-h-60">
                                                {items.filter((i: any) =>
                                                    (i.id === row.itemId) ||
                                                    (
                                                        (itemCategoryFilter === 'ALL' || i.category === itemCategoryFilter) &&
                                                        (itemJobFilter === 'ALL' || (i.commonFor && i.commonFor.includes(itemJobFilter)) || (!i.commonFor && itemJobFilter === 'ALL'))
                                                    )
                                                ).map((item: any) => (
                                                    <SelectItem key={item.id} value={item.id}>
                                                        {item.code} - {item.name}
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </TableCell>
                                    <TableCell>
                                        <Input value={row.unit} disabled className="bg-slate-50" />
                                    </TableCell>
                                    <TableCell>
                                        <Input
                                            type="number"
                                            min="0"
                                            value={row.quantity || ''}
                                            onChange={(e) => handleQuantityChange(idx, e.target.value)}
                                        />
                                    </TableCell>
                                    <TableCell>
                                        <Button variant="ghost" size="sm" onClick={() => handleRemoveRow(idx)}>
                                            <Trash className="w-4 h-4 text-red-500" />
                                        </Button>
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>

                    <div className="p-4 border-t flex justify-center">
                        <Button variant="outline" size="sm" onClick={handleAddRow}>
                            <Plus className="w-4 h-4 mr-2" /> Add Item
                        </Button>
                    </div>
                </CardContent>
            </Card>

            <div className="flex justify-end gap-3">
                <Button variant="outline" onClick={() => router.back()}>Cancel</Button>
                <Button onClick={handleSubmit} disabled={issueMutation.isPending}>
                    {issueMutation.isPending ? 'Processing...' : (
                        <>
                            <Save className="w-4 h-4 mr-2" /> Issue Materials
                        </>
                    )}
                </Button>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import { toast } from "sonner";
import { Plus, Trash2, Send, Loader2 } from "lucide-react";
import Sidebar from '@/components/Sidebar';
import Header from '@/components/Header';

interface InventoryItem {
    id: string;
    code: string;
    name: string;
    unit: string;
    category: string;
}

interface ReturnItem {
    itemId: string;
    quantity: string;
    reason: string;
}

export default function MRNCreatePage() {
    const queryClient = useQueryClient();
    const [selectedStore, setSelectedStore] = useState<string>("");
    const [returnType, setReturnType] = useState<string>("DEFECTIVE");
    const [returnTo, setReturnTo] = useState<string>("SLT");
    const [supplier, setSupplier] = useState<string>("");
    const [generalReason, setGeneralReason] = useState<string>("");
    const [returnItems, setReturnItems] = useState<ReturnItem[]>([]);

    // Fetch stores
    const { data: stores = [] } = useQuery({
        queryKey: ["stores"],
        queryFn: async () => {
            const res = await fetch("/api/stores");
            return res.json();
        }
    });

    // Fetch all inventory items
    const { data: items = [] } = useQuery<InventoryItem[]>({
        queryKey: ["inventory-items"],
        queryFn: async () => {
            const res = await fetch("/api/inventory/items");
            return res.json();
        }
    });

    const getCurrentUserId = () => {
        const user = localStorage.getItem('user');
        if (user) {
            return JSON.parse(user).id;
        }
        return null;
    };

    const createMRNMutation = useMutation({
        mutationFn: async (data: any) => {
            const res = await fetch("/api/inventory/mrn", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(data)
            });
            if (!res.ok) throw new Error("Failed to create MRN");
            return res.json();
        },
        onSuccess: (data) => {
            toast.success(`MRN created! #${data.mrnNumber}`);
            queryClient.invalidateQueries({ queryKey: ["mrns"] });
            // Reset form
            setReturnItems([]);
            setSelectedStore("");
            setGeneralReason("");
            setSupplier("");
        },
        onError: () => toast.error("Failed to create MRN")
    });

    const addNewRow = () => {
        setReturnItems([...returnItems, { itemId: "", quantity: "", reason: "" }]);
    };

    const removeItem = (index: number) => {
        setReturnItems(returnItems.filter((_, i) => i !== index));
    };

    const updateItem = (index: number, field: keyof ReturnItem, value: string) => {
        const updated = [...returnItems];
        updated[index][field] = value;
        setReturnItems(updated);
    };

    const handleSubmit = () => {
        if (!selectedStore) {
            toast.error("Please select a store");
            return;
        }

        const userId = getCurrentUserId();
        if (!userId) {
            toast.error("User not authenticated");
            return;
        }

        const validItems = returnItems.filter(
            item => item.itemId && item.quantity && parseFloat(item.quantity) > 0
        );

        if (validItems.length === 0) {
            toast.error("Please add at least one item");
            return;
        }

        const payload = {
            storeId: selectedStore,
            returnType,
            returnTo,
            supplier: supplier || null,
            reason: generalReason || null,
            returnedById: userId,
            items: validItems.map(item => ({
                itemId: item.itemId,
                quantity: parseFloat(item.quantity),
                reason: item.reason || null
            }))
        };

        createMRNMutation.mutate(payload);
    };

    const getItemDetails = (itemId: string) => {
        return items.find(i => i.id === itemId);
    };

    return (
        <div className="flex h-screen bg-slate-50 overflow-hidden">
            <Sidebar />
            <main className="flex-1 flex flex-col min-w-0 h-full">
                <Header />
                <div className="flex-1 overflow-y-auto p-6">
                    <div className="max-w-6xl mx-auto space-y-4">

                        {/* Header */}
                        <div className="flex justify-between items-center">
                            <div>
                                <h1 className="text-xl font-bold text-slate-900">Material Return Note (MRN)</h1>
                                <p className="text-sm text-slate-500">Return defective, excess, or unused materials</p>
                            </div>
                            <div className="flex gap-2">
                                <Button onClick={addNewRow} variant="outline" size="sm">
                                    <Plus className="w-4 h-4 mr-1" />
                                    Add Item
                                </Button>
                                <Button
                                    onClick={handleSubmit}
                                    disabled={createMRNMutation.isPending || returnItems.length === 0}
                                    size="sm"
                                >
                                    {createMRNMutation.isPending ? (
                                        <Loader2 className="w-4 h-4 mr-1 animate-spin" />
                                    ) : (
                                        <Send className="w-4 h-4 mr-1" />
                                    )}
                                    Submit MRN ({returnItems.length})
                                </Button>
                            </div>
                        </div>

                        {/* MRN Details */}
                        <Card>
                            <CardContent className="p-4 space-y-4">
                                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                    {/* Store */}
                                    <div>
                                        <label className="text-sm font-medium mb-1 block">Store *</label>
                                        <select
                                            className="flex h-9 w-full rounded-md border border-input bg-background px-3 py-1 text-sm focus:outline-none focus:ring-2 focus:ring-ring"
                                            value={selectedStore}
                                            onChange={(e) => setSelectedStore(e.target.value)}
                                        >
                                            <option value="">Select Store...</option>
                                            {stores.map((store: any) => (
                                                <option key={store.id} value={store.id}>{store.name}</option>
                                            ))}
                                        </select>
                                    </div>

                                    {/* Return Type */}
                                    <div>
                                        <label className="text-sm font-medium mb-1 block">Return Type *</label>
                                        <select
                                            className="flex h-9 w-full rounded-md border border-input bg-background px-3 py-1 text-sm"
                                            value={returnType}
                                            onChange={(e) => setReturnType(e.target.value)}
                                        >
                                            <option value="DEFECTIVE">Defective</option>
                                            <option value="EXCESS">Excess</option>
                                            <option value="UNUSED">Unused</option>
                                            <option value="WRONG_DELIVERY">Wrong Delivery</option>
                                        </select>
                                    </div>

                                    {/* Return To */}
                                    <div>
                                        <label className="text-sm font-medium mb-1 block">Return To *</label>
                                        <select
                                            className="flex h-9 w-full rounded-md border border-input bg-background px-3 py-1 text-sm"
                                            value={returnTo}
                                            onChange={(e) => setReturnTo(e.target.value)}
                                        >
                                            <option value="SLT">SLT</option>
                                            <option value="SUPPLIER">Supplier</option>
                                            <option value="MAIN_STORE">Main Store</option>
                                        </select>
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {/* Supplier */}
                                    <div>
                                        <label className="text-sm font-medium mb-1 block">Supplier (if applicable)</label>
                                        <Input
                                            placeholder="Enter supplier name"
                                            value={supplier}
                                            onChange={(e) => setSupplier(e.target.value)}
                                            className="h-9"
                                        />
                                    </div>

                                    {/* General Reason */}
                                    <div>
                                        <label className="text-sm font-medium mb-1 block">General Reason</label>
                                        <Textarea
                                            placeholder="Describe reason for return..."
                                            value={generalReason}
                                            onChange={(e) => setGeneralReason(e.target.value)}
                                            className="h-9 resize-none"
                                            rows={1}
                                        />
                                    </div>
                                </div>
                            </CardContent>
                        </Card>

                        {/* Items Table */}
                        <Card>
                            <CardContent className="p-0">
                                <div className="overflow-x-auto">
                                    <table className="w-full text-sm">
                                        <thead className="bg-slate-100 border-b">
                                            <tr>
                                                <th className="px-3 py-2 text-left text-xs font-medium text-slate-600 w-8">#</th>
                                                <th className="px-3 py-2 text-left text-xs font-medium text-slate-600">Item</th>
                                                <th className="px-3 py-2 text-left text-xs font-medium text-slate-600 w-24">Unit</th>
                                                <th className="px-3 py-2 text-right text-xs font-medium text-slate-600 w-32">Return Qty</th>
                                                <th className="px-3 py-2 text-left text-xs font-medium text-slate-600">Item Reason</th>
                                                <th className="px-3 py-2 text-center text-xs font-medium text-slate-600 w-16">Action</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {returnItems.length === 0 ? (
                                                <tr>
                                                    <td colSpan={6} className="px-3 py-8 text-center text-slate-500 text-sm">
                                                        No items added. Click "Add Item" to start.
                                                    </td>
                                                </tr>
                                            ) : (
                                                returnItems.map((item, index) => {
                                                    const itemDetails = getItemDetails(item.itemId);
                                                    return (
                                                        <tr key={index} className="border-b hover:bg-slate-50">
                                                            <td className="px-3 py-2 text-slate-500 text-xs">{index + 1}</td>
                                                            <td className="px-3 py-2">
                                                                <select
                                                                    className="w-full h-8 rounded border border-input bg-background px-2 text-sm"
                                                                    value={item.itemId}
                                                                    onChange={(e) => updateItem(index, 'itemId', e.target.value)}
                                                                >
                                                                    <option value="">Select Item...</option>
                                                                    {items.map((invItem) => (
                                                                        <option key={invItem.id} value={invItem.id}>
                                                                            {invItem.code} - {invItem.name}
                                                                        </option>
                                                                    ))}
                                                                </select>
                                                            </td>
                                                            <td className="px-3 py-2">
                                                                {itemDetails && (
                                                                    <Badge variant="secondary" className="text-xs">
                                                                        {itemDetails.unit}
                                                                    </Badge>
                                                                )}
                                                            </td>
                                                            <td className="px-3 py-2">
                                                                <Input
                                                                    type="number"
                                                                    className="h-8 text-right text-sm"
                                                                    placeholder="0"
                                                                    value={item.quantity}
                                                                    onChange={(e) => updateItem(index, 'quantity', e.target.value)}
                                                                    min="0"
                                                                    step="1"
                                                                />
                                                            </td>
                                                            <td className="px-3 py-2">
                                                                <Input
                                                                    className="h-8 text-sm"
                                                                    placeholder="Reason..."
                                                                    value={item.reason}
                                                                    onChange={(e) => updateItem(index, 'reason', e.target.value)}
                                                                />
                                                            </td>
                                                            <td className="px-3 py-2 text-center">
                                                                <Button
                                                                    variant="ghost"
                                                                    size="sm"
                                                                    onClick={() => removeItem(index)}
                                                                    className="h-7 w-7 p-0"
                                                                >
                                                                    <Trash2 className="w-3.5 h-3.5 text-red-500" />
                                                                </Button>
                                                            </td>
                                                        </tr>
                                                    );
                                                })
                                            )}
                                        </tbody>
                                    </table>
                                </div>
                            </CardContent>
                        </Card>

                        {/* Info */}
                        <div className="bg-amber-50 border border-amber-200 rounded-md p-3">
                            <p className="text-xs text-amber-900">
                                <strong>Note:</strong> MRN requires approval before stock is reduced. Status: PENDING → APPROVED → Stock Reduced
                            </p>
                        </div>
                    </div>
                </div>
            </main>
        </div>
    );
}

